// ─── Hash Table in JavaScript ────────────────────────────────────────────────
//
// JavaScript's Map object is a hash table with O(1) avg operations.
// Keys can be any type (objects, primitives) — unlike plain objects.
// Below: built-in Map, then a manual separate-chaining implementation.

// ── Built-in Map ──────────────────────────────────────────────────────────
const map = new Map();
map.set('name', 'Alice');     // O(1) insert
map.set('age', 30);           // O(1) insert
map.get('name');              // O(1) → 'Alice'
map.has('age');               // O(1) → true
map.delete('age');            // O(1)
map.size;                     // O(1) → 1

// Iteration is insertion-order guaranteed (unlike object keys)
for (const [key, value] of map) {
  console.log(key, value);
}

// ── Manual separate chaining hash table ──────────────────────────────────
class HashMap {
  constructor(capacity = 16) {
    this.capacity = capacity;
    this.buckets  = Array.from({ length: capacity }, () => []);
    this.size     = 0;
    this.LOAD_THRESHOLD = 0.75;
  }

  // Hash function: polynomial rolling hash
  #hash(key) {
    const s = String(key);
    let h = 0;
    for (let i = 0; i < s.length; i++)
      h = (h * 31 + s.charCodeAt(i)) % this.capacity;
    return h;
  }

  // O(1) avg — Insert or update
  set(key, value) {
    const idx   = this.#hash(key);
    const chain = this.buckets[idx];
    const entry = chain.find(e => e.key === key);
    if (entry) { entry.value = value; return; }  // update
    chain.push({ key, value });                   // insert
    this.size++;
    if (this.size / this.capacity > this.LOAD_THRESHOLD) this.#resize();
  }

  // O(1) avg — Get value
  get(key) {
    const idx   = this.#hash(key);
    const entry = this.buckets[idx].find(e => e.key === key);
    return entry?.value ?? undefined;
  }

  // O(1) avg — Check existence
  has(key) {
    const idx = this.#hash(key);
    return this.buckets[idx].some(e => e.key === key);
  }

  // O(1) avg — Delete
  delete(key) {
    const idx     = this.#hash(key);
    const chain   = this.buckets[idx];
    const entryIdx = chain.findIndex(e => e.key === key);
    if (entryIdx === -1) return false;
    chain.splice(entryIdx, 1);
    this.size--;
    return true;
  }

  // O(n) — Resize (doubles capacity, rehashes all)
  #resize() {
    const old = this.buckets;
    this.capacity *= 2;
    this.buckets  = Array.from({ length: this.capacity }, () => []);
    this.size     = 0;
    for (const chain of old)
      for (const { key, value } of chain)
        this.set(key, value);  // rehash into new buckets
  }

  get loadFactor() { return this.size / this.capacity; }
}

// Usage
const ht = new HashMap();
ht.set('name', 'Alice');
ht.set('age', 30);
console.log(ht.get('name'));  // 'Alice'
console.log(ht.has('age'));   // true
ht.delete('age');
console.log(ht.loadFactor);   // 0.0625

// ─── Hash Table in Java ──────────────────────────────────────────────────────
//
// java.util.HashMap — separate chaining, resizes at load factor 0.75.
// java.util.LinkedHashMap — insertion-order preserving HashMap.
// java.util.TreeMap — sorted by key, O(log n) ops (not a hash table).
// java.util.Hashtable — legacy, synchronized, avoid in new code.
// java.util.concurrent.ConcurrentHashMap — thread-safe, segment locking.

import java.util.*;

public class HashMapExamples {
    public static void main(String[] args) {

        // ── Built-in HashMap ─────────────────────────────────────────────
        HashMap<String, Integer> map = new HashMap<>();
        map.put("name", 1);              // O(1) avg insert
        map.put("age",  2);              // O(1) avg insert
        map.get("name");                 // O(1) avg → 1
        map.containsKey("age");          // O(1) avg → true
        map.remove("age");               // O(1) avg
        map.size();                      // O(1) → 1

        // getOrDefault — safe get with fallback
        int val = map.getOrDefault("missing", 0);

        // computeIfAbsent — insert only if absent (atomic)
        map.computeIfAbsent("count", k -> 0);

        // merge — frequency counting pattern
        String[] words = {"a", "b", "a", "c", "b", "a"};
        Map<String, Integer> freq = new HashMap<>();
        for (String w : words)
            freq.merge(w, 1, Integer::sum);  // {a:3, b:2, c:1}

        // Iteration
        for (Map.Entry<String, Integer> e : freq.entrySet())
            System.out.println(e.getKey() + " = " + e.getValue());
    }

    // ── Two Sum using HashMap — O(n) ──────────────────────────────────────
    static int[] twoSum(int[] nums, int target) {
        Map<Integer, Integer> seen = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            int complement = target - nums[i];
            if (seen.containsKey(complement))
                return new int[]{seen.get(complement), i};
            seen.put(nums[i], i);
        }
        return new int[]{};
    }

    // ── Group anagrams — O(n·k) where k = avg word length ────────────────
    static Map<String, List<String>> groupAnagrams(String[] words) {
        Map<String, List<String>> groups = new HashMap<>();
        for (String w : words) {
            char[] ch = w.toCharArray();
            Arrays.sort(ch);                     // sort chars as key
            String key = new String(ch);
            groups.computeIfAbsent(key, k -> new ArrayList<>()).add(w);
        }
        return groups;
    }
}

// ─── Hash Table in C++ ───────────────────────────────────────────────────────
//
// std::unordered_map — separate chaining, O(1) avg ops.
// std::unordered_set — same but keys only (no values).
// std::map            — red-black tree, O(log n) ops, sorted.
// robin_hood::unordered_map (3rd party) — best performance in practice.

#include <unordered_map>
#include <unordered_set>
#include <string>
#include <vector>

int main() {
    // ── Built-in unordered_map ────────────────────────────────────────────
    std::unordered_map<std::string, int> map;
    map["name"] = 1;              // O(1) avg insert / update
    map.insert({"age", 2});       // O(1) avg insert (no overwrite)
    map.count("name");            // O(1) → 1 (exists)
    map.at("name");               // O(1) → 1 (throws if missing)
    map.erase("age");             // O(1) avg delete
    map.size();                   // O(1)

    // find — returns iterator (safer than operator[])
    auto it = map.find("name");
    if (it != map.end())
        std::string val = it->second;  // O(1)

    // Reserve capacity to avoid rehashing (O(n))
    map.reserve(1000);            // pre-allocate for 1000 elements
    map.max_load_factor(0.7f);    // set custom load threshold

    // ── Custom hash for user types ────────────────────────────────────────
    struct PairHash {
        size_t operator()(const std::pair<int,int>& p) const {
            return std::hash<int>()(p.first) ^ (std::hash<int>()(p.second) << 32);
        }
    };
    std::unordered_map<std::pair<int,int>, int, PairHash> pairMap;

    // ── Two Sum — O(n) ───────────────────────────────────────────────────
    auto twoSum = [](std::vector<int>& nums, int target) {
        std::unordered_map<int, int> seen;
        for (int i = 0; i < (int)nums.size(); i++) {
            auto it = seen.find(target - nums[i]);
            if (it != seen.end())
                return std::make_pair(it->second, i);
            seen[nums[i]] = i;
        }
        return std::make_pair(-1, -1);
    };

    return 0;
}
